# --- Configuration ---
my $PLUGIN_DIR = $ENV{PLUGIN_DIR} || './plugins';
my $LOG_FILE   = $ENV{PLUGIN_LOG} || './plugin_execution.log';
my $TIMEOUT    = $ENV{PLUGIN_TIMEOUT} || 5;  # seconds

# --- Allowed plugin directory (absolute path for security) ---
my $ALLOWED_PLUGIN_DIR = File::Spec->rel2abs($PLUGIN_DIR);

# --- Logging utility ---
sub log_message {
    my ($level, $message) = @_;
    my $timestamp = localtime();
    my $log_line = "[$timestamp] [$level] $message\n";
    print STDERR $log_line;
    if (open(my $fh, '>>', $LOG_FILE)) {
        print $fh $log_line;
        close $fh;
    }
}

# --- Security: Validate plugin code before execution ---
sub validate_plugin_code {
    my ($code, $plugin_name) = @_;
    my @violations;

    # Disallow dangerous operations
    my @forbidden_patterns = (
        { pattern => qr/\bsystem\s*\(/, desc => 'system() calls' },
        { pattern => qr/\bexec\s*\(/,   desc => 'exec() calls' },
        { pattern => qr/\bqx\s*[\{\(\[\/]/, desc => 'qx// backtick execution' },
        { pattern => qr/`[^`]*`/,        desc => 'backtick execution' },
        { pattern => qr/\bopen\s*\(\s*\$?\w+\s*,\s*['"]\s*\|/, desc => 'piped open()' },
        { pattern => qr/\|\s*['"]\s*\)/, desc => 'piped open() (write)' },
        { pattern => qr/\bunlink\s*\(/,  desc => 'unlink() file deletion' },
        { pattern => qr/\brmdir\s*\(/,   desc => 'rmdir() directory deletion' },
        { pattern => qr/\brename\s*\(/,  desc => 'rename() file operations' },
        { pattern => qr/\bchmod\s*\(/,   desc => 'chmod() permission changes' },
        { pattern => qr/\bchown\s*\(/,   desc => 'chown() ownership changes' },
        { pattern => qr/\bkill\s*\(/,    desc => 'kill() signal sending' },
        { pattern => qr/\bfork\s*\(/,    desc => 'fork() process creation' },
        { pattern => qr/\beval\s*\(/,    desc => 'nested eval() calls' },
        { pattern => qr/\bBEGIN\s*\{/,   desc => 'BEGIN blocks' },
        { pattern => qr/\bEND\s*\{/,     desc => 'END blocks' },
        { pattern => qr/\brequire\s+/,   desc => 'require statements' },
        { pattern => qr/\buse\s+/,       desc => 'use statements (use approved modules via sandbox)' },
        { pattern => qr/\bdo\s+['"]/, desc => 'do FILE execution' },
        { pattern => qr/\bSocket\b/,     desc => 'Socket operations' },
        { pattern => qr/\bIO::Socket\b/, desc => 'IO::Socket operations' },
        { pattern => qr/\bsymlink\s*\(/, desc => 'symlink creation' },
    );

    for my $rule (@forbidden_patterns) {
        if ($code =~ $rule->{pattern}) {
            push @violations, "Forbidden: $rule->{desc}";
        }
    }

    if (@violations) {
        my $msg = "Plugin '$plugin_name' failed security validation:\n"
                . join("\n", map { "  - $_" } @violations);
        log_message('SECURITY', $msg);
        return (0, $msg);
    }

    log_message('INFO', "Plugin '$plugin_name' passed security validation.");
    return (1, 'OK');
}

# --- Parse a plugin configuration file ---
sub parse_plugin_config {
    my ($filepath) = @_;

    # Security: ensure the file is within the allowed directory
    my $abs_path = File::Spec->rel2abs($filepath);
    unless ($abs_path =~ /^\Q$ALLOWED_PLUGIN_DIR\E/) {
        log_message('SECURITY', "Rejected plugin outside allowed directory: $abs_path");
        return undef;
    }

    unless (-f $filepath && -r $filepath) {
        log_message('ERROR', "Plugin config not found or not readable: $filepath");
        return undef;
    }

    # Check file permissions - warn if world-writable
    my @stat = stat($filepath);
    if ($stat[2] & 002) {
        log_message('SECURITY', "WARNING: Plugin file is world-writable: $filepath — skipping for safety.");
        return undef;
    }

    open(my $fh, '<', $filepath) or do {
        log_message('ERROR', "Cannot open plugin config '$filepath': $!");
        return undef;
    };

    my %config;
    my $in_code_block = 0;
    my $code_buffer = '';

    while (my $line = <$fh>) {
        chomp $line;

        # End of code block
        if ($in_code_block && $line =~ /^__END_CODE__\s*$/) {
            $in_code_block = 0;
            $config{code} = $code_buffer;
            next;
        }

        # Accumulate code lines
        if ($in_code_block) {
            $code_buffer .= $line . "\n";
            next;
        }

        # Skip comments and blank lines
        next if $line =~ /^\s*#/ || $line =~ /^\s*$/;

        # Start of code block
        if ($line =~ /^__BEGIN_CODE__\s*$/) {
            $in_code_block = 1;
            $code_buffer = '';
            next;
        }

        # Key=Value pairs
        if ($line =~ /^\s*(\w+)\s*=\s*(.+?)\s*$/) {
            $config{lc($1)} = $2;
        }
    }
    close $fh;

    # Validate required fields
    unless ($config{name} && $config{version} && $config{code}) {
        log_message('ERROR', "Plugin config '$filepath' missing required fields (name, version, code).");
        return undef;
    }

    $config{filepath} = $abs_path;
    $config{enabled} = ($config{enabled} // 'true') eq 'true' ? 1 : 0;

    return \%config;
}

# --- Execute plugin code safely with eval ---
sub execute_plugin {
    my ($plugin, $context) = @_;
    $context //= {};

    my $plugin_name = $plugin->{name};
    my $plugin_code = $plugin->{code};

    unless ($plugin->{enabled}) {
        log_message('INFO', "Plugin '$plugin_name' is disabled — skipping.");
        return { success => 0, skipped => 1, message => 'Plugin disabled' };
    }

    # Step 1: Validate the code
    my ($valid, $validation_msg) = validate_plugin_code($plugin_code, $plugin_name);
    unless ($valid) {
        return { success => 0, error => $validation_msg };
    }

    # Step 2: Build sandboxed code wrapper
    # The plugin code runs in its own package namespace with a shared context hash.
    my $sandbox_package = "PluginSandbox::$plugin_name";
    $sandbox_package =~ s/[^A-Za-z0-9_:]/_/g;  # sanitize package name

    my $wrapped_code = qq{
        package $sandbox_package;
        no strict 'refs';
        sub run_plugin {
            my (\$ctx) = \@_;
            my \%result;
            # Plugin helper: set a result value
            local *set_result = sub { \$result{\$_[0]} = \$_[1]; };
            # Plugin helper: get context value
            local *get_context = sub { return \$ctx->{\$_[0]}; };
            # Plugin helper: log from plugin
            local *plugin_log = sub { main::log_message('PLUGIN', "[$plugin_name] \$_[0]"); };

            # --- Begin user plugin code ---
            $plugin_code
            # --- End user plugin code ---

            return \\%result;
        }
        1;
    };

    # Step 3: Execute with timeout protection
    my $result;
    my $eval_error;

    log_message('INFO', "Executing plugin '$plugin_name' v$plugin->{version} (timeout: ${TIMEOUT}s)...");

    eval {
        local $SIG{ALRM} = sub { die "Plugin '$plugin_name' exceeded timeout of ${TIMEOUT}s\n" };
        alarm($TIMEOUT);

        # First eval: compile the sandbox package
        eval $wrapped_code;
        if ($@) {
            die "Compilation error in plugin '$plugin_name': $@\n";
        }

        # Second: call the run_plugin function
        {
            no strict 'refs';
            my $runner = \&{"${sandbox_package}::run_plugin"};
            $result = $runner->($context);
        }

        alarm(0);
    };
    $eval_error = $@;
    alarm(0);  # ensure alarm is cleared

    if ($eval_error) {
        log_message('ERROR', "Plugin '$plugin_name' execution failed: $eval_error");
        return { success => 0, error => $eval_error };
    }

    log_message('INFO', "Plugin '$plugin_name' executed successfully.");
    return { success => 1, result => $result };
}

# --- Load all plugins from the plugin directory ---
sub load_all_plugins {
    unless (-d $PLUGIN_DIR) {
        log_message('WARN', "Plugin directory '$PLUGIN_DIR' does not exist. Creating it.");
        mkdir $PLUGIN_DIR or do {
            log_message('ERROR', "Cannot create plugin directory: $!");
            return [];
        };
    }

    opendir(my $dh, $PLUGIN_DIR) or do {
        log_message('ERROR', "Cannot open plugin directory '$PLUGIN_DIR': $!");
        return [];
    };

    my @plugin_files = grep { /\.plugin\.conf$/ && -f "$PLUGIN_DIR/$_" } readdir($dh);
    closedir $dh;

    my @plugins;
    for my $file (sort @plugin_files) {
        my $filepath = "$PLUGIN_DIR/$file";
        log_message('INFO', "Loading plugin config: $filepath");
        my $plugin = parse_plugin_config($filepath);
        if ($plugin) {
            push @plugins, $plugin;
            log_message('INFO', "Loaded plugin: $plugin->{name} v$plugin->{version} (enabled: $plugin->{enabled})");
        }
    }

    return \@plugins;
}

