# --- Display results ---
sub display_results {
    my ($plugin_name, $outcome) = @_;

    print "\n" . "=" x 60 . "\n";
    print "Plugin: $plugin_name\n";
    print "-" x 60 . "\n";

    if ($outcome->{skipped}) {
        print "Status: SKIPPED ($outcome->{message})\n";
    } elsif ($outcome->{success}) {
        print "Status: SUCCESS\n";
        if (ref $outcome->{result} eq 'HASH') {
            print "Results:\n";
            for my $key (sort keys %{$outcome->{result}}) {
                printf "  %-25s => %s\n", $key, $outcome->{result}{$key} // '(undef)';
            }
        }
    } else {
        print "Status: FAILED\n";
        print "Error: $outcome->{error}\n";
    }
    print "=" x 60 . "\n";
}

